#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static int g_allocs = 0;
static int g_frees = 0;
static size_t g_total_bytes = 0;

void *tracked_malloc(size_t size) {
    void *ptr = malloc(size);
    if (ptr) {
        g_allocs++;
        g_total_bytes += size;
    }
    return ptr;
}

void tracked_free(void *ptr) {
    if (ptr) {
        free(ptr);
        g_frees++;
    }
}

void leak_report(void) {
    printf("=== Leak Report ===\n");
    printf("allocs: %d\n", g_allocs);
    printf("frees:  %d\n", g_frees);
    printf("total bytes: %zu\n", g_total_bytes);
    if (g_allocs == g_frees)
        printf("Status: OK\n");
    else
        printf("LEAK: %d bloc(s) non libere(s)\n", g_allocs - g_frees);
}

int main(void) {
    char *a = tracked_malloc(32);
    char *b = tracked_malloc(64);
    char *c = tracked_malloc(16);

    strcpy(a, "hello");
    strcpy(b, "world");
    strcpy(c, "leak");

    tracked_free(a);
    tracked_free(b);
